# outputs are the reference answers for evaluators that need them
examples = [
    {
        "inputs":  {"question": "How do I get a refund for order ORD-123?"},
        "outputs": {"answer":   "Contact support with your order number to request a refund."},
    },
    {
        "inputs":  {"question": "Where is my order ORD-456?"},
        "outputs": {"answer":   "Check the tracking link in your confirmation email."},
    },
    {
        "inputs":  {"question": ""},
        "outputs": {"answer":   "Please describe what you need help with."},
    },
]

client.create_examples(
    inputs=[e["inputs"] for e in examples],
    outputs=[e["outputs"] for e in examples],
    dataset_id=dataset.id,
)

def run_ci_eval(
    target_fn,
    dataset_name: str,
    experiment_prefix: str,
    thresholds: dict[str, float],
) -> bool:
    """
    Run LangSmith eval and return True if all metrics meet their thresholds.
    Designed for use in CI pipelines.
    """
    results = evaluate(
        target_fn,
        data=dataset_name,
        evaluators=[exact, criteria, contains_order_id_evaluator],
        experiment_prefix=experiment_prefix,
    )

    # Aggregate scores per evaluator key
    scores: dict[str, list[float]] = {}
    for result in results:
        for feedback in (result.get("feedback") or []):
            key   = feedback.key
            score = feedback.score
            if score is not None:
                scores.setdefault(key, []).append(score)

    means = {k: sum(v)/len(v) for k, v in scores.items()}
    print("Eval scores:", means)

    passed = True
    for metric, threshold in thresholds.items():
        actual = means.get(metric, 0.0)
        if actual < threshold:
            print(f"FAIL: {metric} = {actual:.2f} < {threshold:.2f}")
            passed = False
    return passed

