from langsmith import Client

client = Client()

def compare_experiments(dataset_name: str, exp_a: str, exp_b: str):
    """Fetch aggregate scores for two experiments and show the delta."""
    results = {}
    for exp_name in (exp_a, exp_b):
        runs = list(client.list_runs(
            project_name=exp_name,
            execution_order=1,
            error=False,
        ))
        # Collect feedback scores keyed by run id
        scores: dict[str, dict[str, float]] = {}
        for run in runs:
            feedback = list(client.list_feedback(run_ids=[run.id]))
            for fb in feedback:
                scores.setdefault(run.id, {})[fb.key] = fb.score
        # Average per metric
        from collections import defaultdict
        metric_totals: dict[str, list[float]] = defaultdict(list)
        for run_scores in scores.values():
            for key, val in run_scores.items():
                if val is not None:
                    metric_totals[key].append(val)
        results[exp_name] = {k: sum(v)/len(v) for k, v in metric_totals.items()}

    print(f"Metric          {exp_a:<20} {exp_b:<20} Delta")
    print("-" * 70)
    all_keys = set(results[exp_a]) | set(results[exp_b])
    for key in sorted(all_keys):
        a_val = results[exp_a].get(key, 0.0)
        b_val = results[exp_b].get(key, 0.0)
        delta = b_val - a_val
        flag = " ✓" if delta > 0.02 else (" ✗" if delta < -0.02 else "")
        print(f"{key:<16} {a_val:.3f}               {b_val:.3f}               {delta:+.3f}{flag}")

compare_experiments(
    dataset_name="support-agent-v1",
    exp_a="support-agent-baseline",
    exp_b="support-agent-chain-of-thought",
)
